const t=".prompt-optimizer-btn{display:flex;align-items:center;justify-content:center;gap:8px;background:linear-gradient(135deg,#6366f1,#a855f7);color:#fff;border:none;border-radius:9999px;padding:8px 16px;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Helvetica,Arial,sans-serif;font-size:14px;font-weight:500;cursor:pointer;box-shadow:0 4px 6px -1px #0000001a,0 2px 4px -1px #0000000f;transition:all .2s ease-in-out;z-index:999999;margin-bottom:8px}.prompt-optimizer-btn:hover{transform:translateY(-2px);box-shadow:0 10px 15px -3px #0000001a,0 4px 6px -2px #0000000d}.prompt-optimizer-btn:disabled{opacity:.7;cursor:not-allowed;transform:none}.prompt-optimizer-icon{width:16px;height:16px}.prompt-optimizer-spin{animation:prompt-optimizer-spin 1s linear infinite}@keyframes prompt-optimizer-spin{0%{transform:rotate(0)}to{transform:rotate(360deg)}}";export{t as s};
